#!/usr/bin/env bash
# 0-1-10-ip.sh — 国内独立创作者全生命周期：公众号 0 → 1 万粉 → 10 万粉 → 全职收入（广告 + 知识付费 + 个人 IP） SOP walkthrough for 内容创作者经济(Substack / Beehiiv / 公众号 / 知识星球 / 小报童 / Patreon — newsletter 写作 + 订阅制变现 + 受众沉淀 + 个人 IP).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="内容创作者经济(Substack / Beehiiv / 公众号 / 知识星球 / 小报童 / Patreon — newsletter 写作 + 订阅制变现 + 受众沉淀 + 个人 IP)"
WORKFLOW="国内独立创作者全生命周期：公众号 0 → 1 万粉 → 10 万粉 → 全职收入（广告 + 知识付费 + 个人 IP）"

usage() {
  cat <<EOF
0-1-10-ip.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./0-1-10-ip.sh             # interactive
  ./0-1-10-ip.sh --dry-run
  ./0-1-10-ip.sh --json
  ./0-1-10-ip.sh --explain
  ./0-1-10-ip.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "国内独立创作者全生命周期：公众号 0 → 1 万粉 → 10 万粉 → 全职收入（广告 + 知识付费 + 个人 IP）" 工作流。

一句话: 一个中国大陆独立创作者从「零粉丝」走到「靠内容全职」的完整路径。与海外路径**形态根本不同**——主阵地是微信公众号（生态封闭、迁移成本高），主收入不是订阅而是**流量主广告 + 接单广告 + 知识付费 + 下游个人 IP 变现**。intake 明确要求两条路径分开画，这一条是国内侧。

入门 SOP 共 17 步, 失败模式自检 5 项。

相关心智模型:
  • 平台是聚合者,创作者是租户 — 资产要握在自己手里: newsletter / 创作者经济里,平台(Substack / 公众号)靠控制需求与分发赢,创作者在平台上是租户;真正的资产是「能带走的 email 列表 + 自有域名(海外)/ 私域回流(国内)
  • 「先免费建信任、再变现」的耐心模型: 这一行的资深人默认「受众信任 / 受众深度」是前置资产,变现是它的函数 — 顺序不能反:先把价值无偿给出去、把漏斗顶部做够宽,再谈收费 / 接广告 / 卖课。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**选垂直定位**：精准为王，聚焦一个细分人群的具体需求——哪怕只服务 1 类人，也比「大而全」有价值。"
  "**建号 + 选主体**：注册公众号（订阅号为主），同步开视频号 / 小红书作引流位（公众号自身几乎没有公域分发）。"
  "**定更新节奏**：日更或两天一更——国内公众号生态对「频率」的要求高于海外（无算法推荐红利，靠勤补）。"
  "**多平台引流**：在知乎 / 小红书 / 视频号 / 知识星球发内容导流到公众号（公众号是「沉淀池」不是「获客池」）。"
  "**过关 + 开流量主**：粉丝过 500 即可开流量主（推文即有广告分成收益）；这是国内第一个、也是门槛最低的变现口。"
  "**守节奏 + 打爆款**：稳定高频输出，争取单篇阅读破千、出 1-2 篇小爆款建立识别度。"
  "**做矩阵 / 互推**：与同量级账号互推、在知识星球等「同频付费社群」发帖获取精准粉丝。"
  "**强化留存**：留存比涨粉重要——1000 个活跃粉丝 > 1 万沉默粉丝；引导加个人微信 / 进群做私域回流。"
  "**过关条件**：~1 万粉 + 有稳定阅读基本盘 + 有可识别的内容标签。"
  "**接单广告**：1 万粉起可接软广 / 硬广，报价随粉丝量和垂直度涨（行业惯例：粉丝越多、越垂直，单条报价越高）。"
  "**上知识付费**：把知识打包成专栏 / 课程 / 训练营 / 付费社群（知识星球 / 小报童 / 得到）——这是国内创作者收入的核心形态，对应海外的 paid subscription 但更偏「打包课程」。"
  "**建私域产品**：社群会员 / 一对一咨询 / 电商带货按 niche 选配。"
  "**过关条件**：广告 + 知识付费 + 私域三条里至少两条跑通，单月收入起量。"
  "**流程化 + 团队化**：内容生产、社群运营、广告对接流程化，可外包。"
  "**个人 IP 多元化**（国内主导流派）：内容是信用积累器，真生意在下游——出书 / 演讲 / 顾问 / 投资 / 线下课。"
  "**抗合规风险**：关注自媒体许可证、算法备案、平台对营销号清理、税务对头部自媒体的核查——这些是国内特有的、需月度校准的变量。"
  "**过关条件**：收入稳定 + 不只依赖单一平台单一变现 + 合规上没有硬伤。"
)
declare -a FAILURE_MODES=(
  "**只在公众号发、不做外部引流**：公众号无公域推荐，新号增长几乎为零。避免：把视频号 / 小红书当获客口，公众号当沉淀池。"
  "**纯靠广告变现**：收入受平台政策和广告大盘支配、天花板低。避免：阶段 2 必须同步上知识付费 + 私域产品。"
  "**不做私域回流**：粉丝全留在平台体系，限流 / 封号即资产清零。避免：阶段 1 就引导高价值粉丝进个人微信 / 社群。"
  "**合规裸奔**：做大后才发现许可证 / 税务问题。避免：阶段 3 之前合规前置。"
  "**照搬海外 Substack 订阅制 playbook**：国内读者付费习惯、平台生态完全不同，订阅制在国内基本跑不通。避免：用国内「广告 + 知识付费 + 个人 IP」组合，不套海外模型。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "0-1-10-ip-walkthrough"
fi
